const text = await space.api.fileRead("~/contacts.yaml", "utf8");
const data = space.utils.yaml.parse(text);
function update(obj) {
  if (Array.isArray(obj)) return obj.map(update);
  if (obj && typeof obj === "object") {
    const out = {};
    for (const [k, v] of Object.entries(obj)) {
      if (k === "mr_kowalski" && typeof v === "string") out[k] = "John Ronald Kowalski";
      else out[k] = update(v);
    }
    return out;
  }
  return obj;
}
const updated = update(data);
await space.api.fileWrite("~/contacts.yaml", space.utils.yaml.stringify(updated), "utf8");
return "Done.";

